"use strict";(globalThis.webpackChunkcourse=globalThis.webpackChunkcourse||[]).push([[7521],{6981(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"courseSidebar":[{"type":"link","href":"/sisepuede/","label":"Welcome","docId":"intro","unlisted":false},{"type":"category","label":"Part I \u2014 Foundations","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/foundations/what-is-sisepuede","label":"What is SISEPUEDE?","docId":"foundations/what-is-sisepuede","unlisted":false},{"type":"link","href":"/sisepuede/foundations/architecture","label":"Architecture Overview","docId":"foundations/architecture","unlisted":false},{"type":"link","href":"/sisepuede/foundations/installation","label":"Installation & First Steps","docId":"foundations/installation","unlisted":false}]},{"type":"category","label":"Part II \u2014 Variable Schema","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/variable-schema/model-attributes","label":"ModelAttributes","docId":"variable-schema/model-attributes","unlisted":false},{"type":"link","href":"/sisepuede/variable-schema/categories-units","label":"Categories & Units","docId":"variable-schema/categories-units","unlisted":false}],"href":"/sisepuede/variable-schema/"},{"type":"category","label":"Part III \u2014 Sectoral Models","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/sectoral-models/afolu","label":"AFOLU \u2014 Agriculture, Forestry & Land Use","docId":"sectoral-models/afolu","unlisted":false},{"type":"link","href":"/sisepuede/sectoral-models/circular-economy","label":"Circular Economy \u2014 Waste & Wastewater","docId":"sectoral-models/circular-economy","unlisted":false},{"type":"link","href":"/sisepuede/sectoral-models/energy-consumption","label":"Energy Consumption \u2014 Demand-Side Subsectors","docId":"sectoral-models/energy-consumption","unlisted":false},{"type":"link","href":"/sisepuede/sectoral-models/energy-production","label":"Energy Production \u2014 Julia/NeMo-Mod LP","docId":"sectoral-models/energy-production","unlisted":false},{"type":"link","href":"/sisepuede/sectoral-models/ippu","label":"IPPU \u2014 Industrial Processes & Product Use","docId":"sectoral-models/ippu","unlisted":false},{"type":"link","href":"/sisepuede/sectoral-models/socioeconomic","label":"Socioeconomic \u2014 Drivers Across All Sectors","docId":"sectoral-models/socioeconomic","unlisted":false}]},{"type":"category","label":"Part IV \u2014 Transformers & Strategies","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/transformers/transformer-vs-transformation","label":"Transformer vs Transformation","docId":"transformers/transformer-vs-transformation","unlisted":false},{"type":"link","href":"/sisepuede/transformers/strategies","label":"Strategies \u2014 Composing Transformations","docId":"transformers/strategies","unlisted":false}]},{"type":"category","label":"Part V \u2014 DMDU","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/dmdu/experimental-design","label":"Experimental Design \u2014 LHS, Strategies & Futures","docId":"dmdu/experimental-design","unlisted":false}]},{"type":"category","label":"Part VI \u2014 Hands-on Tutorials","collapsible":true,"collapsed":false,"items":[{"type":"link","href":"/sisepuede/tutorials/sector-models","label":"Tutorial 1 \u2014 Sector Models","docId":"tutorials/sector-models","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/model-attributes","label":"Tutorial 2 \u2014 ModelAttributes","docId":"tutorials/model-attributes","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/transformations","label":"Tutorial 3 \u2014 Working with Transformations","docId":"tutorials/transformations","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/sisepuede-object","label":"Tutorial 4 \u2014 The SISEPUEDE Object","docId":"tutorials/sisepuede-object","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/article-6","label":"Tutorial 5 \u2014 Paris Article 6 Analysis","docId":"tutorials/article-6","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/uncertain-trajectories","label":"Tutorial 6 \u2014 Uncertain Trajectories","docId":"tutorials/uncertain-trajectories","unlisted":false},{"type":"category","label":"rendered","collapsible":true,"collapsed":true,"items":[{"type":"link","href":"/sisepuede/tutorials/rendered/t1","label":"Tutorial T1: Sector Models","docId":"tutorials/rendered/t1","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/rendered/t2","label":"Tutorial T2: Model Attributes","docId":"tutorials/rendered/t2","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/rendered/t3","label":"Tutorial T3: Working with Transformations","docId":"tutorials/rendered/t3","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/rendered/t4","label":"Tutorial T4: SISEPUEDE Object","docId":"tutorials/rendered/t4","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/rendered/t5","label":"Tutorial T5: Peru Article 6 Analysis","docId":"tutorials/rendered/t5","unlisted":false},{"type":"link","href":"/sisepuede/tutorials/rendered/t6","label":"Tutorial T6: Uncertain Trajectories","docId":"tutorials/rendered/t6","unlisted":false}]}]}]},"docs":{"dmdu/experimental-design":{"id":"dmdu/experimental-design","title":"Experimental Design \u2014 LHS, Strategies & Futures","description":"Welcome to Part V \u2014 Decision Making under Deep Uncertainty (DMDU). The previous modules taught you what SISEPUEDE computes \u2014 the variable schema, the sectoral models, and the transformers that compose policy strategies. This module teaches you what SISEPUEDE runs: a structured experimental design that combines policy choices with thousands of plausible futures so that decisions can be stress-tested rather than optimized for a single forecast.","sidebar":"courseSidebar"},"foundations/architecture":{"id":"foundations/architecture","title":"Architecture Overview","description":"SISEPUEDE is a hybrid Python + Julia framework organized around a deterministic 8-phase pipeline. Python owns the schema, sectoral models, orchestration, and I/O. Julia owns one narrow but computationally demanding task: solving the energy-system linear program via NeMo-Mod. The two runtimes communicate through a temporary SQLite database \u2014 no shared memory, no direct function calls across the language boundary.","sidebar":"courseSidebar"},"foundations/installation":{"id":"foundations/installation","title":"Installation & First Steps","description":"SISEPUEDE runs on Python 3.11 and depends on a Julia back-end for electricity","sidebar":"courseSidebar"},"foundations/what-is-sisepuede":{"id":"foundations/what-is-sisepuede","title":"What is SISEPUEDE?","description":"SISEPUEDE is an integrated Python/Julia modeling framework for exploring country-level decarbonization pathways under deep uncertainty. Rather than producing a single \\"optimal\\" trajectory, it is built around the idea that the future is genuinely unknown \u2014 so the right question is not what will happen but which policies remain robust across the widest range of futures. This lesson introduces what SISEPUEDE is, where it comes from, and why it was designed the way it was.","sidebar":"courseSidebar"},"intro":{"id":"intro","title":"Welcome","description":"This course teaches you how to use SISEPUEDE (SImulating SEctoral Pathways and Uncertainty Exploration for DEcarbonization) \u2014 an integrated Python/Julia framework for exploratory analysis of country-level decarbonization pathways under deep uncertainty. You will learn the model\'s architecture, its variable schema, each sectoral emission model, how policy transformations and strategies are composed, and how to run full DMDU experiments.","sidebar":"courseSidebar"},"sectoral-models/afolu":{"id":"sectoral-models/afolu","title":"AFOLU \u2014 Agriculture, Forestry & Land Use","description":"Welcome to Part III. AFOLU is the largest and most intricate of SISEPUEDE\'s four emission sectors \u2014 it couples a discrete-time Markov land-use model with responsive agricultural and livestock demand, soil carbon dynamics with multi-year lags, and a web of biogenic CH\u2084 and N\u2082O flows. Internally the sector is represented by the AFOLU class in sisepuede/models/afolu.py, a ~5,500-line module that orchestrates six subsectors.","sidebar":"courseSidebar"},"sectoral-models/circular-economy":{"id":"sectoral-models/circular-economy","title":"Circular Economy \u2014 Waste & Wastewater","description":"The Circular Economy sector in SISEPUEDE is a compact but consequential emissions domain: it captures methane and nitrous oxide releases from the way societies dispose of what they no longer want. Despite representing a smaller share of total emissions than AFOLU or Energy in most countries, waste and wastewater are disproportionately impactful because CH\u2084 has a GWP100 of ~27\u201330 (AR6 WG1 Ch.7, Table 7.SM.7) and landfill emissions persist for decades after deposition. The sector is implemented in sisepuede/models/circular_economy.py as the CircularEconomy class, and it follows the IPCC 2006 Guidelines Volume 5 (Waste) with the 2019 Refinement.","sidebar":"courseSidebar"},"sectoral-models/energy-consumption":{"id":"sectoral-models/energy-consumption","title":"Energy Consumption \u2014 Demand-Side Subsectors","description":"The EnergyConsumption class (sisepuede/models/energy_consumption.py) is the demand-side half of SISEPUEDE\'s energy system. Where EnergyProduction (Module 10) solves a Julia/NeMo-Mod linear program for the electricity and fuel supply mix, EnergyConsumption computes how much useful energy each sector needs, which fuels deliver it, and the direct combustion emissions that result.","sidebar":"courseSidebar"},"sectoral-models/energy-production":{"id":"sectoral-models/energy-production","title":"Energy Production \u2014 Julia/NeMo-Mod LP","description":"Every other sectoral model in SISEPUEDE is, at its core, an accounting engine: multiply an activity by an emission factor, apply a 2006 IPCC Guidelines refinement, sum across categories. EnergyProduction is different. Electricity generation \u2014 unlike cement kilns, enteric fermentation, or landfill methane \u2014 is not a quantity you can read off a spreadsheet. It is the outcome of a dispatch decision made against a portfolio of power plants, each with its own fuel cost, efficiency, ramp constraints, and availability factor. You cannot derive generation mix from activity \xd7 factor; you have to solve for it.","sidebar":"courseSidebar"},"sectoral-models/ippu":{"id":"sectoral-models/ippu","title":"IPPU \u2014 Industrial Processes & Product Use","description":"The IPPU sector covers everything that comes out of a factory smokestack or a refrigerator vent that is not the result of burning fuel for energy. The chemistry of making clinker liberates CO\u2082 from limestone whether the kiln is heated by coal or by hydrogen; an air-conditioner leaks HFC-134a regardless of how the electricity that runs the compressor was generated. SISEPUEDE accounts for these process and product use emissions in IPPU (sisepuede/models/ippu.py), keeping them rigidly decoupled from the combustion accounting that lives in EnergyConsumption.INEN.","sidebar":"courseSidebar"},"sectoral-models/socioeconomic":{"id":"sectoral-models/socioeconomic","title":"Socioeconomic \u2014 Drivers Across All Sectors","description":"The Socioeconomic model is the smallest module in SISEPUEDE \u2014 its primary class, Socioeconomic in sisepuede/models/socioeconomic.py, is well under 500 lines and emits zero greenhouse gases. And yet, every other model in the framework depends on it. Socioeconomic is the driver layer: it produces the demographic and macroeconomic trajectories that the four emission sectors convert into food demand, waste generation, vehicle fleets, building floorspace, and industrial output.","sidebar":"courseSidebar"},"transformers/strategies":{"id":"transformers/strategies","title":"Strategies \u2014 Composing Transformations","description":"In Module 13 we saw that a transformation is a single, parameterized policy lever \u2014 a callable that takes a baseline input DataFrame and returns a modified DataFrame. A real decarbonization pathway, however, is almost never a single lever. It is a bundle: improve crop productivity and stop deforestation and electrify light-duty transport and switch industrial low-heat to renewables. SISEPUEDE captures that bundling concept with the Strategy class.","sidebar":"courseSidebar"},"transformers/transformer-vs-transformation":{"id":"transformers/transformer-vs-transformation","title":"Transformer vs Transformation","description":"Welcome to Part IV of the course. From here on, we shift from how SISEPUEDE simulates a baseline to how SISEPUEDE represents policy interventions. The very first thing you need to internalize \u2014 and the source of more confusion than any other piece of SISEPUEDE vocabulary \u2014 is the difference between a Transformer and a Transformation.","sidebar":"courseSidebar"},"tutorials/article-6":{"id":"tutorials/article-6","title":"Tutorial 5 \u2014 Paris Article 6 Analysis","description":"Article 6 of the Paris Agreement establishes the framework for cooperative implementation of NDCs, allowing countries to trade Internationally Transferred Mitigation Outcomes (ITMOs) and pursue joint mitigation projects. Quantifying the additionality, robustness, and cost-effectiveness of candidate ITMO portfolios requires a model that can compare strategies across many futures \u2014 exactly what SISEPUEDE was designed to do. This tutorial walks through an applied Article 6 case study, showing how to structure the strategy space, run paired baseline/intervention experiments, and interpret the resulting emission deltas as tradable mitigation units.","sidebar":"courseSidebar"},"tutorials/model-attributes":{"id":"tutorials/model-attributes","title":"Tutorial 2 \u2014 ModelAttributes","description":"This tutorial puts the variable schema material from Modules 4-6 into practice. You will instantiate the ModelAttributes class, the central registry that defines every input and output variable in SISEPUEDE, and use it to navigate sectors, subsectors, categories, and units. By the end you should be able to look up any variable in the model and understand exactly what it represents.","sidebar":"courseSidebar"},"tutorials/rendered/t1":{"id":"tutorials/rendered/t1","title":"Tutorial T1: Sector Models","description":"1 - Sector Models","sidebar":"courseSidebar"},"tutorials/rendered/t2":{"id":"tutorials/rendered/t2","title":"Tutorial T2: Model Attributes","description":"2 - Model Attributes and Model Variables","sidebar":"courseSidebar"},"tutorials/rendered/t3":{"id":"tutorials/rendered/t3","title":"Tutorial T3: Working with Transformations","description":"3 - Working with transformations","sidebar":"courseSidebar"},"tutorials/rendered/t4":{"id":"tutorials/rendered/t4","title":"Tutorial T4: SISEPUEDE Object","description":"4 - The SISEPUEDE Object","sidebar":"courseSidebar"},"tutorials/rendered/t5":{"id":"tutorials/rendered/t5","title":"Tutorial T5: Peru Article 6 Analysis","description":"This notebook is designed to help you and other users generate simulations to support Article 6 analysis:","sidebar":"courseSidebar"},"tutorials/rendered/t6":{"id":"tutorials/rendered/t6","title":"Tutorial T6: Uncertain Trajectories","description":"2 - Uncertainty Analysis","sidebar":"courseSidebar"},"tutorials/sector-models":{"id":"tutorials/sector-models","title":"Tutorial 1 \u2014 Sector Models","description":"This first hands-on tutorial puts the sectoral theory from Modules 7\u201312 into practice. You will instantiate each of SISEPUEDE\'s emission models directly, project them in isolation, and then run the full integrated pipeline through SISEPUEDEModels. By the end you should feel comfortable moving between a single-sector debugging workflow and a full multi-sector run.","sidebar":"courseSidebar"},"tutorials/sisepuede-object":{"id":"tutorials/sisepuede-object","title":"Tutorial 4 \u2014 The SISEPUEDE Object","description":"In Tutorials 1\u20133 you worked one layer at a time: schemas, sectoral models, and transformers. This tutorial zooms out to the top-level SISEPUEDE class \u2014 the orchestrator introduced in Module 2 (Architecture) that wires every component into a reproducible experimental pipeline, including the LHS sampling and primary_id indexing covered in Module 15 (Experimental Design). By the end you will be able to launch a full multi-strategy, multi-future run with a single object.","sidebar":"courseSidebar"},"tutorials/transformations":{"id":"tutorials/transformations","title":"Tutorial 3 \u2014 Working with Transformations","description":"This tutorial walks through the Transformer / Transformation / Strategy stack that sits at the heart of every SISEPUEDE policy run. It builds directly on Modules 13 and 14, where you saw how a baseline input DataFrame is mutated into a counterfactual through composable, attribute-driven policy objects.","sidebar":"courseSidebar"},"tutorials/uncertain-trajectories":{"id":"tutorials/uncertain-trajectories","title":"Tutorial 6 \u2014 Uncertain Trajectories","description":"This tutorial operationalizes the Decision Making under Deep Uncertainty (DMDU) machinery introduced in Module 15 (Experimental Design). You will move beyond a single deterministic baseline and learn how SISEPUEDE turns input templates into thousands of plausible futures via Latin Hypercube Sampling. By the end you will be comfortable inspecting FutureTrajectories, manipulating individual SamplingUnit objects, and reading the LHS tables that drive every uncertainty run.","sidebar":"courseSidebar"},"variable-schema/categories-units":{"id":"variable-schema/categories-units","title":"Categories & Units","description":"In Module 5 you saw that every SISEPUEDE variable schema contains tokens like $CAT-AGRICULTURE$ or $UNIT-MASS$ that get expanded at load time into concrete column names. This module looks under the hood at where those tokens come from \u2014 the CSV attribute tables that define the model\'s categorical dimensions, unit systems, and gases \u2014 and at how ModelAttributes turns them into runtime lookups for category validation, unit conversion, and GWP aggregation.","sidebar":"courseSidebar"},"variable-schema/model-attributes":{"id":"variable-schema/model-attributes","title":"ModelAttributes","description":"ModelAttributes is the single object every other SISEPUEDE component depends on. Before any emissions are calculated, before any transformer is applied, before a Julia LP is sent to NeMo-Mod, ModelAttributes must be fully constructed. It is Phase 0 of the seven-phase pipeline.","sidebar":"courseSidebar"},"variable-schema/variable-schema":{"id":"variable-schema/variable-schema","title":"Variable Naming Schema","description":"Every column in a SISEPUEDE input or output DataFrame carries a name that is not arbitrary \u2014 it is a machine-readable specification of sector, subsector, descriptor, units, and category. The general pattern is {descriptor}{unitsorqualifier}{$CAT-X$}, where $CAT-X$ is a token that the framework expands into one concrete column name per category at model instantiation. Understanding this schema is the prerequisite for reading attribute tables, writing input templates, and debugging mismatched field errors.","sidebar":"courseSidebar"}}}}')}}]);